document.querySelectorAll(".faq-question, .accordion-header").forEach(e=>{e.setAttribute("role","button"),e.setAttribute("tabindex","0");const t=()=>e.closest(".faq-item, .accordion-item")?.classList.toggle("active");e.addEventListener("click",t),e.addEventListener("keydown",e=>{"Enter"!==e.key&&" "!==e.key||t()})});